var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"그르, 그르르으…….","JPN":"グルル、グルルル……","ENG":"Grr... Grrrrrrr...","TWN":"呃嗚嗚嗚嗚……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_05"},{"id":"L9_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"저건 침식체……?","JPN":"あれは、侵食体……？","ENG":"Isn't that...a C.O....?","TWN":"那是侵蝕體……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L12_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"어이, 스완!! 이건 말이 다르잖아!?","JPN":"ちょっと、スワン！　話が違うじゃん！？","ENG":"Hey, Swan!! This is different from what you just told me!","TWN":"喂，史旺！！這和說好的不一樣啊！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L13_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"달의 뒷면, 세피로트 나무, 세계를 만드는 법칙……. 실컷 잘난 척하더니, 그 결과가 이거야?","JPN":"月の裏側、セフィロト、世界を作る法則……さんざん偉そうなこと言っておいて、その結果がこれなの？","ENG":"The dark side of the moon, the Tree of Sephiroth, the law of creating a world... After being such a show-off, this is the result of it?","TWN":"月亮背面、生命樹、創造世界的法則……說這麼多，結果就是這樣嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"어디서 듣도 보도 못한 신종 침식체가 나타난 거?","JPN":"見たこともない新種の侵食体が現れたじゃん！","ENG":"A new type of C.O. appearing?","TWN":"就是幾隻聞所未聞的新型侵蝕體？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"거 참, 대단한 발견이시네!","JPN":"まったく、たいそうな発見だね！","ENG":"Wow! What an extraordinary discovery!","TWN":"哎呀，真是了不起的發現啊！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"모든 힘에는 작용과 반작용이 있기 마련이죠.","JPN":"すべての力には、作用と反作用というものが存在します。","ENG":"All forces have action and reaction.","TWN":"所有的力量都會有作用和反作用。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"게임 이후, 세계의 변화가 무조건 긍정적인 방향일 것이라고 확신한 적은 없습니다만.","JPN":"ゲームの後、世界に訪れる変化のすべてがポジティブな形であるとは断定していません。","ENG":"After the Game, I didn't say the world would change for the better with certainty.","TWN":"雖然我從未保證遊戲結束之後，世界的變化一定會往積極的方向。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"현 단계에서 저것이 세피라에 의해 발생한 것이라 단정짓는 것조차 일러요.","JPN":"現段階では、あれがセフィラの影響で発生したものかどうかもわかりません。","ENG":"It's still too early to even conclude if that was due to Sephira in this phase.","TWN":"現在就斷定那是由塞菲拉引起的還為時過早。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"우선은 상황을 조금 더…….","JPN":"まずは状況をもう少し……","ENG":"First of all, we should observe the situation further–","TWN":"再了解一下情況比較好，總之先……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"됐어! 난 지루한 건 딱 질색이거든!?","JPN":"ああもういい！　あたしはね、退屈なのは大っ嫌いなの。","ENG":"No! You know how I hate waiting!","TWN":"夠了！我最討厭無聊了！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"네 장단이라면 이미 맞춰 줄 만큼 충분히 맞춰줬잖아?","JPN":"今まで十分つき合ったでしょ？","ENG":"And I've already done enough doing what you want!","TWN":"你的要求我已經配合得夠多了吧？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그러니까 이젠 내가 나설 차례라고……!!","JPN":"だからここはあたしの出番……！！","ENG":"Now, it's my turn–!","TWN":"所以現在該按照我的方式來了……！！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신, 제 말을 듣지 않는군요.","JPN":"私の言うことを聞かないのですね。","ENG":"Why do you never listen to me?","TWN":"你根本沒在聽我說話吧？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제가 조금 더 지켜보자고 했을 텐데요?","JPN":"先ほど、状況を見守ると言ったはずです。","ENG":"I said we should first observe, did I not?","TWN":"我應該是說過再觀察一下吧？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"미쳤어? 이게 무슨 개짓거리야!","JPN":"マジで言ってんの？　ふざけないで！","ENG":"Are you crazy? What was that for?!","TWN":"你瘋了嗎？那是為什麼！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"그르르……!","JPN":"グルル……！","ENG":"Grr...!","TWN":"嘎……！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_05"},{"id":"L33_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"으으……!","JPN":"ぐう……！","ENG":"Urgh...!","TWN":"呃呃……！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"제길, 도망치잖아! 저리 비켜!","JPN":"くそ、逃げてくじゃん！　どいてよ！","ENG":"Dammit, it's getting away! Out of the way!","TWN":"該死，逃跑了！讓開！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L37_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"어쩌자는 거야! 뭔지도 모르는 위험 요소를 이 세상에 풀어 버릴 생각이야?","JPN":"どういうつもり！　得体の知れない危険要素をこの世に野放しにしてもいいっていうの！？","ENG":"What do you want me to do, huh?! Are you just going to let some unknown danger run wild in this world?","TWN":"你在幹什麼！打算放任這些不明的危險因素流入這個世界嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"……상관없습니다.","JPN":"……構いません。","ENG":"...It doesn’t matter.","TWN":"……那些無所謂。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"뭐?","JPN":"は？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"배우를 속이려고 하다니, 우습군요.","JPN":"役者をだまそうとするだなんて、面白いですね。","ENG":"Trying to fool an actress, how amusing.","TWN":"拙劣的把戲，竟然還想要欺騙演員，真是可笑。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L42_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"게임이 끝났으니 우리 동맹은 여기까지라는 뜻입니다. 리트리버.","JPN":"ゲームは終わりました。私たちの同盟もここまでという意味です、レトリーバー。","ENG":"It means that the Game is over and our truce ends here, retriever.","TWN":"遊戲結束，我們的合作到此為止，獵犬。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그동안 당신이 제 뒤를 캐고 다녔다는 걸, 모를 줄 알았나요?","JPN":"今まであなたがこっそり私について調査していたこと、バレていないとでも思っていましたか？","ENG":"Did you think that I wouldn't know that you've been prying on my business all this time?","TWN":"你以為我不知道你一直在背後調查我嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"……큭큭.","JPN":"……くくっ。","ENG":"...Keke.","TWN":"……咳咳。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"뭐야, 이제야 본색을 드러내는군.","JPN":"なんだ、やっと本性を見せる気になったんだ。","ENG":"So now you show your true colors.","TWN":"什麼啊，現在才露出真面目。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"대장 말이 딱 맞네. 뒤통수 치는 거 기다리느라 목 빠지는 줄 알았다고?","JPN":"隊長の言ったとおりだね。裏切るのを待つのもだるかったんだよ？","ENG":"Commander was right about you. I was wondering when you'd stab us in the back.","TWN":"看來被隊長說對了。只不過等你背後捅刀等得我脖子都長了？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제 호위로 당신이 따라붙은 것 자체가 대장님의 지령이었겠죠.","JPN":"私の護衛であなたがつき添ったのは、隊長の指令だったのでしょう。","ENG":"It must be Commander's orders placing you as my guard.","TWN":"你跟著我保護我的行動，應該是隊長的指令吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L1_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"저를 따라서 세계의 변화를 목격하고. 변수가 될지도 모르는 그 싹을 제거하기 위해서.","JPN":"私と共に世界の変化を目撃し、変数になりえるかもしれない芽を摘むために。","ENG":"You were tasked to follow me and witness the change of the world, and to remove anything that could become a variable.","TWN":"跟隨我見證世界的變化，並消除那些可能成為變數的萌芽。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그리고 게임이 끝난 뒤에도 제가 당신들과 함께할지, 그렇지 않을지 시험하기 위해서.","JPN":"そしてゲームが終わった後も私があなたたちと行動をともにするか、そうでないか試すために。","ENG":"Also, it was a test to see if I would continue our pact after the Game was over.","TWN":"而且為了測試結束之後我是否會繼續和你們在一起。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"애초에 대장님은 다루지 못할 변수는 철저하게 배제하는 편이니까요.","JPN":"隊長は、制御できない変数は徹底的に排除するタイプですから。","ENG":"For I know that Commander tends to completely exclude variables that he can't handle.","TWN":"畢竟隊長一向會徹底排除無法掌控的變數。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 저에게 있어, 이 변수는 무척이나 중요한 분기점입니다.","JPN":"ですが私にとって、この変数はとても大事な分岐点になります。","ENG":"But for me, this variable is a critical turning point.","TWN":"但對我來說，這個變數是個非常重要的分岔點。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L9_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그러니 세피라의 실체가 무엇인지 정확히 규정하기 전까지는 아무것도 건드릴 수 없어요.","JPN":"ですからセフィラの正体を究明できるまで、なにも触れるわけにはいきません。","ENG":"So, until I am able to define what Sephira's true form is, I will not allow anyone to touch it.","TWN":"所以在明確界定塞菲拉的實質之前，誰也不能碰。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그래? 그럼, 이것도 알고 있으려나?","JPN":"そう？　じゃあ、これも知ってるかな？","ENG":"Oh yeah? Then, did you also know about this?","TWN":"是嗎？那這些你也知道嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"난 말이야. 널 처음 본 순간부터 마음에 안 들었거든?","JPN":"あたしさ、初めてあんたを見た時から気に入らなかったんだよね。","ENG":"You know, I didn't like you since the second I met you.","TWN":"實話說，我從第一眼開始就不喜歡你。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그래서 항상 그 잘난 낯짝을 날려버리고 싶었단 말이지……!!","JPN":"その偉そうなツラに、いつか一発食らわせてやりたかった……！！","ENG":"I always wanted to land a blow to that haughty face of yours...!!","TWN":"所以我一直想把那張自以為是的臉給打飛……！！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"이렇게……!!","JPN":"こうやってね……！！","ENG":"Just like this...!!","TWN":"就像這樣……！！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"……물론이에요. 퍼스트윙.","JPN":"……もちろんです、ファーストウイング。","ENG":"...Of course, I did, Firstwing.","TWN":"……我知道。弗斯特薇。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_THUD"},{"id":"L18_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"인간을 관찰하고 그 내면을 탐구하는 건, 배우의 업이랍니다.","JPN":"役者として、人間を観察し内面を探求するのは当たり前のことです。","ENG":"It's an actress' job to observe people and explore their minds.","TWN":"觀察人類並探索他們的內心，是演員的職責。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신이 누구인지, 당신의 세계가 어떻게 멸망했는지, 당신의 분노가 무엇에서 기인하는지.","JPN":"あなたが誰なのか、あなたの世界がどうして滅びたか、あなたの怒りは何に起因するものか。","ENG":"Who you are, how your world came to collapse, and where your anger stems from.","TWN":"你是誰，你的世界是如何毀滅的，你的憤怒源自何處。"},"stage":{"bg":"SWANSONG_01","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_FIRE_03"},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"저는 누구보다도 깊게 이해하고 있으니까요.","JPN":"私は誰よりもよく理解しています。","ENG":"I understand them deeper than anyone else.","TWN":"我比任何人都更清楚。"},"stage":{"bg":"SWANSONG_01","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"너……! 설마, 그 날개는……!","JPN":"あんた……！　その翼、まさか……！","ENG":"You...! Those wings...!","TWN":"你……！那些翅膀是……！"},"stage":{"bg":"SWANSONG_01","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L27_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"왜냐하면…….","JPN":"なぜなら……","ENG":"Because...","TWN":"要怪就怪……"},"stage":{"bg":"SWANSONG_01","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신들은 배우 앞에서 너무 많은 걸 보여줬어요.","JPN":"あなたたちは、俳優の前であまりにも多くのものを見せてしまった。","ENG":"you have exposed yourself too much in front of the actress.","TWN":"你們在演員面前演得未免太過頭。"},"stage":{"bg":"SWANSONG_01","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"VOICE_UNIT_SIXWING_CA_ACTOR_BATTLE_START_1"}]`);export{e as default};